// buildFileNode 递归构建文件节点
func (s *FiletreeHandler) buildFileNode(absPath, relativePath string, info os.FileInfo, maxDepth int32, includeHidden bool, currentDepth int32) (*v1.FileNode, error) {
	// 跳过隐藏文件（以.开头）
	if !includeHidden && strings.HasPrefix(info.Name(), ".") {
		return nil, nil
	}

	node := &v1.FileNode{
		Name:         info.Name(),
		Path:         relativePath,
		IsDir:        info.IsDir(),
		Size:         info.Size(),
		ModifiedTime: info.ModTime().UnixMilli(),
	}

	// 如果是目录，递归读取子文件
	// maxDepth: -1 表示无限深度，0 表示只展开当前层（列出子项但不递归），1 表示展开两层，以此类推
	if info.IsDir() && (maxDepth == -1 || currentDepth <= maxDepth) {
		entries, err := os.ReadDir(absPath)
		if err != nil {
			logger.Warn("Failed to read directory %s: %v", absPath, err)
			return node, nil // 返回节点但不包含子节点
		}

		children := make([]*v1.FileNode, 0)
		fileCount := int32(0)

		for _, entry := range entries {
			// 跳过隐藏文件
			if !includeHidden && strings.HasPrefix(entry.Name(), ".") {
				continue
			}

			entryInfo, err := entry.Info()
			if err != nil {
				logger.Warn("Failed to get info for %s: %v", entry.Name(), err)
				continue
			}

			childPath := filepath.Join(relativePath, entry.Name())
			childAbsPath := filepath.Join(absPath, entry.Name())

			childNode, err := s.buildFileNode(childAbsPath, childPath, entryInfo, maxDepth, includeHidden, currentDepth+1)
			if err != nil || childNode == nil {
				continue
			}

			children = append(children, childNode)
			if !childNode.IsDir {
				fileCount++
			}
		}

		node.Children = children
		node.FileCount = &fileCount
	}

	return node, nil
}

// DownloadFile
// @route /apis/v1/filetree/download [GET]
