	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil, fmt.Errorf("file not found: %s", req.Path)
		}
		return nil, nil, fmt.Errorf("failed to stat file: %w", err)
	}

	// 检查是否是目录
	if info.IsDir() {
		return nil, nil, fmt.Errorf("cannot download directory: %s", req.Path)
	}

	// 读取文件内容
	content, err := os.ReadFile(absPath)
	if err != nil {
		return nil, nil, fmt.Errorf("failed to read file: %w", err)
	}

	// 准备响应头
	headers := map[string]string{
		"Content-Type":        mime.TypeByExtension(filepath.Ext(req.Path)),
		"Content-Disposition": fmt.Sprintf("attachment; filename=\"%s\"", filepath.Base(req.Path)),
		"Content-Length":      fmt.Sprintf("%d", len(content)),
	}

	return content, headers, nil
