func (s *FiletreeHandler) DeleteFile(ctx context.Context, req *v1.DeleteFileRequest) *baseV1.Response {
	// TODO: 实现管理员权限检查
	// TODO: 获取用户名，判断是否为 admin

	// 获取绝对路径
	absPath, err := s.getAbsolutePath(req.Path)
	if err != nil {
		return baseV1.Failed(err, int64(baseV1.BaseErrorCode_INVALID_PARAM))
	}

	// 检查文件/目录是否存在
	info, err := os.Stat(absPath)
	if err != nil {
		if os.IsNotExist(err) {
			return baseV1.Failed(
				fmt.Errorf("path not found: %s", req.Path),
				int64(baseV1.BaseErrorCode_NOT_FOUND),
			)
		}
		return baseV1.Failed(err, int64(baseV1.BaseErrorCode_INTERNAL_ERROR))
	}

	// 如果是目录
	if info.IsDir() {
		recursive := false
		if req.Recursive != nil {
			recursive = *req.Recursive
		}

		if recursive {
			// 递归删除
			if err := os.RemoveAll(absPath); err != nil {
				return baseV1.Failed(
					fmt.Errorf("failed to delete directory recursively: %w", err),
					int64(baseV1.BaseErrorCode_INTERNAL_ERROR),
				)
			}
		} else {
			// 只删除空目录
			if err := os.Remove(absPath); err != nil {
				return baseV1.Failed(
					fmt.Errorf("failed to delete directory (may not be empty): %w", err),
					int64(baseV1.BaseErrorCode_INTERNAL_ERROR),
				)
			}
		}
	} else {
		// 删除文件
		if err := os.Remove(absPath); err != nil {
			return baseV1.Failed(
				fmt.Errorf("failed to delete file: %w", err),
				int64(baseV1.BaseErrorCode_INTERNAL_ERROR),
			)
		}
	}

	logger.Info("Path deleted successfully: %s (is_dir: %v)", req.Path, info.IsDir())

	result := map[string]interface{}{
		"path":    req.Path,
		"deleted": true,
	}

	return baseV1.Success(baseV1.WithData(result))
}

// CreateDir
// @route /apis/v1/filetree/mkdir [POST]
// 二期功能：仅管理员可用
func (s *FiletreeHandler) CreateDir(ctx context.Context, req *v1.CreateDirRequest) *baseV1.Response {
	// TODO: 实现管理员权限检查
	// TODO: 获取用户名，判断是否为 admin

	// 获取绝对路径
	absPath, err := s.getAbsolutePath(req.Path)
	if err != nil {
		return baseV1.Failed(err, int64(baseV1.BaseErrorCode_INVALID_PARAM))
	}

	// 检查目录是否已存在
	if _, err := os.Stat(absPath); err == nil {
		return baseV1.Failed(
			fmt.Errorf("directory already exists: %s", req.Path),
			int64(baseV1.BaseErrorCode_RESOURCE_ALREADY_EXISTS),
		)
	}

	// 创建目录
	recursive := false
	if req.Recursive != nil {
		recursive = *req.Recursive
	}

	if recursive {
		// 递归创建父目录
		if err := os.MkdirAll(absPath, 0755); err != nil {
			return baseV1.Failed(
				fmt.Errorf("failed to create directory recursively: %w", err),
				int64(baseV1.BaseErrorCode_INTERNAL_ERROR),
			)
		}
	} else {
		// 只创建当前目录（父目录必须存在）
		if err := os.Mkdir(absPath, 0755); err != nil {
			return baseV1.Failed(
				fmt.Errorf("failed to create directory: %w", err),
				int64(baseV1.BaseErrorCode_INTERNAL_ERROR),
			)
		}
	}

	logger.Info("Directory created successfully: %s", req.Path)

	// 返回目录信息
	info, _ := os.Stat(absPath)
	result := map[string]interface{}{
		"path":          req.Path,
		"name":          filepath.Base(req.Path),
		"is_dir":        true,
		"modified_time": info.ModTime().UnixMilli(),
	}

	return baseV1.Success(baseV1.WithData(result))
}

// GetFilesByPaths 批量获取文件信息
// @route /apis/v1/filetree/batch [POST]
func (s *FiletreeHandler) GetFilesByPaths(ctx context.Context, req *v1.GetFilesByPathsRequest) *baseV1.Response {
	paths := req.GetPaths()
	if len(paths) == 0 {
		return baseV1.Failed(fmt.Errorf("paths cannot be empty"), int64(baseV1.BaseErrorCode_INVALID_PARAM))
	}

	// 批量获取文件信息
	files := make([]*v1.FileNode, 0, len(paths))
	notFound := make([]string, 0)

	for _, path := range paths {
		// 获取绝对路径
		absPath, err := s.getAbsolutePath(path)
		if err != nil {
			notFound = append(notFound, path)
			continue
		}

		// 获取文件信息
		info, err := os.Stat(absPath)
		if err != nil {
			notFound = append(notFound, path)
			continue
		}

		// 构建 FileNode
		node := &v1.FileNode{
			Name:         info.Name(),
			Path:         path,
			IsDir:        info.IsDir(),
			Size:         info.Size(),
			ModifiedTime: info.ModTime().UnixMilli(),
		}

		// 如果是目录，统计文件数量
		if info.IsDir() {
			entries, err := os.ReadDir(absPath)
			if err == nil {
				fileCount := int32(len(entries))
				node.FileCount = &fileCount
			}
		}

		files = append(files, node)
	}

	return baseV1.Success(baseV1.WithData(map[string]interface{}{
		"files":     files,
		"not_found": notFound,
	}))
}



